// Generated by Claude Opus 4.6

import { screen } from '@testing-library/react';
import React from 'react';
import { Provider } from 'react-redux';
import { MemoryRouter, Route, Routes } from 'react-router-dom';
import { Store } from 'redux';

import DevfilesListContainer from '@/containers/DevfilesList';
import getComponentRenderer from '@/services/__mocks__/getComponentRenderer';
import { AppThunk } from '@/store';
import { MockStoreBuilder } from '@/store/__mocks__/mockStore';
import { actionCreators, LocalDevfile } from '@/store/LocalDevfiles';

const mockRequestDevfiles = jest.fn();
const mockCreateDevfile = jest.fn();
const mockDeleteDevfile = jest.fn();

jest.mock('@/store/LocalDevfiles', () => {
  const original =
    jest.requireActual<typeof import('@/store/LocalDevfiles')>('@/store/LocalDevfiles');
  return {
    ...original,
    actionCreators: {
      ...original.actionCreators,
      requestDevfiles: (): AppThunk => async () => {
        mockRequestDevfiles();
      },
      createDevfile:
        (name: string, description: string, content: string): AppThunk<Promise<string>> =>
        async () => {
          mockCreateDevfile(name, description, content);
          return 'new-id';
        },
      deleteDevfile:
        (id: string): AppThunk =>
        async () => {
          mockDeleteDevfile(id);
        },
    } as typeof actionCreators,
  };
});

jest.mock('@/pages/DevfilesList', () => {
  const FakeDevfilesList = (props: {
    devfiles: LocalDevfile[];
    error: string | undefined;
    isLoading: boolean;
    namespace: string;
    defaultDevfileContent: string | undefined;
  }): React.ReactElement => {
    return (
      <div data-testid="devfiles-list-page">
        <span data-testid="devfiles-count">{props.devfiles.length}</span>
        <span data-testid="is-loading">{String(props.isLoading)}</span>
        <span data-testid="namespace">{props.namespace}</span>
        {props.error && <span data-testid="error">{props.error}</span>}
        {props.defaultDevfileContent && (
          <span data-testid="default-content">{props.defaultDevfileContent}</span>
        )}
      </div>
    );
  };
  FakeDevfilesList.displayName = 'DevfilesList';
  return FakeDevfilesList;
});

const { renderComponent } = getComponentRenderer(getComponent);

describe('DevfilesList Container', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  it('should request devfiles on mount', () => {
    const store = buildStore();
    renderComponent(store);

    expect(mockRequestDevfiles).toHaveBeenCalledTimes(1);
  });

  it('should render the DevfilesList page', () => {
    const store = buildStore();
    renderComponent(store);

    expect(screen.getByTestId('devfiles-list-page')).toBeInTheDocument();
  });

  it('should pass devfiles from the store', () => {
    const devfiles = createTestDevfiles(3);
    const store = buildStore({ devfiles });
    renderComponent(store);

    expect(screen.getByTestId('devfiles-count')).toHaveTextContent('3');
  });

  it('should pass isLoading from the store', () => {
    const store = buildStore({ isLoading: true });
    renderComponent(store);

    expect(screen.getByTestId('is-loading')).toHaveTextContent('true');
  });

  it('should pass error from the store', () => {
    const store = buildStore({ error: 'Something went wrong' });
    renderComponent(store);

    expect(screen.getByTestId('error')).toHaveTextContent('Something went wrong');
  });

  it('should pass namespace from the store', () => {
    const store = buildStore({ namespace: 'test-ns' });
    renderComponent(store);

    expect(screen.getByTestId('namespace')).toHaveTextContent('test-ns');
  });

  it('should pass defaultDevfileContent from the store', () => {
    const devfileContent = 'schemaVersion: 2.2.2\nmetadata:\n  name: empty';
    const emptyWorkspaceUrl = 'https://registry.example.com/devfiles/empty';

    const store = new MockStoreBuilder()
      .withInfrastructureNamespace(
        [{ name: 'test-ns', attributes: { default: 'true', phase: 'Active' } }],
        false,
      )
      .withDevfileRegistries({
        devfiles: {
          [emptyWorkspaceUrl]: { content: devfileContent },
        },
        registries: {
          'https://registry.example.com': {
            metadata: [
              {
                displayName: 'Empty Workspace',
                description: 'An empty workspace',
                tags: ['Empty'],
                icon: '',
                links: { v2: emptyWorkspaceUrl },
              },
            ],
          },
        },
      })
      .build();

    renderComponent(store);

    expect(screen.getByTestId('default-content').textContent).toContain('schemaVersion: 2.2.2');
    expect(screen.getByTestId('default-content').textContent).toContain('name: empty');
  });

  it('should show zero devfiles when store is empty', () => {
    const store = buildStore();
    renderComponent(store);

    expect(screen.getByTestId('devfiles-count')).toHaveTextContent('0');
  });
});

function createTestDevfiles(count: number): LocalDevfile[] {
  return Array.from({ length: count }, (_, i) => ({
    id: `devfile-${i}`,
    name: `Test Devfile ${i}`,
    description: `Description ${i}`,
    content: `schemaVersion: 2.2.2\nmetadata:\n  name: test-${i}`,
    projectNames: [],
    lastModified: new Date().toISOString(),
  }));
}

function buildStore(
  options: {
    devfiles?: LocalDevfile[];
    isLoading?: boolean;
    error?: string;
    namespace?: string;
  } = {},
): Store {
  const { devfiles = [], isLoading = false, error, namespace = 'user-che' } = options;

  return new MockStoreBuilder({
    localDevfiles: {
      devfiles,
      isLoading,
      error,
      agentTerminalUrl: undefined,
      agentPodStatuses: [],
      configMapResourceVersion: '',
    },
  })
    .withInfrastructureNamespace(
      [{ name: namespace, attributes: { default: 'true', phase: 'Active' } }],
      false,
    )
    .build();
}

function getComponent(store: Store): React.ReactElement {
  return (
    <Provider store={store}>
      <MemoryRouter initialEntries={['/devfiles']}>
        <Routes>
          <Route path="/devfiles" element={<DevfilesListContainer />} />
        </Routes>
      </MemoryRouter>
    </Provider>
  );
}
